// Check if the cases form a contiguous range.
static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
  assert(Cases.size() >= 1);

  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1)
      return false;
  }
  return true;
}

// Check if the complement of the cases (within the given range) forms a
// contiguous range. If so, return true and set ComplementStart and
// ComplementSize to the start and size of the complement range.
static bool complementCasesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases,
                                         const ConstantRange &CR,
                                         APInt &ComplementStart,
                                         APInt &ComplementSize) {
  assert(Cases.size() >= 1);
  assert(!CR.isEmptySet() && !CR.isFullSet());

  // Sort the cases
  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);

  // The range must be non-wrapping for this optimization
  if (CR.isWrappedSet())
    return false;

  const APInt &RangeStart = CR.getLower();
  const APInt &RangeEnd = CR.getUpper();
  APInt RangeSize = RangeEnd - RangeStart;

  // The number of cases must be less than the range size for a complement to exist
  if (Cases.size() >= RangeSize.getLimitedValue())
    return false;

  // Compute the complement: values in [RangeStart, RangeEnd) that are not in Cases
  // We need to find if the complement forms a single contiguous range

  // Walk through the range and find gaps
  APInt CurrentPos = RangeStart;
  bool FoundComplement = false;
  APInt FoundStart;
  APInt FoundEnd;

  for (ConstantInt *CI : Cases) {
    const APInt &CaseVal = CI->getValue();

    // Check if there's a gap before this case
    if (CaseVal.ugt(CurrentPos)) {
      // Found a gap [CurrentPos, CaseVal)
      if (FoundComplement) {
        // Already found a complement range, this is a second gap - not contiguous
        return false;
      }
      FoundComplement = true;
      FoundStart = CurrentPos;
      FoundEnd = CaseVal;
    }

    // Move past this case
    CurrentPos = CaseVal + 1;
  }

  // Check if there's a gap after the last case
  if (CurrentPos.ult(RangeEnd)) {
    if (FoundComplement) {
      // Already found a complement range, this is a second gap - not contiguous
      return false;
    }
    FoundComplement = true;
    FoundStart = CurrentPos;
    FoundEnd = RangeEnd;
  }

  if (!FoundComplement)
    return false;

  ComplementStart = FoundStart;
  ComplementSize = FoundEnd - FoundStart;
  return true;
}
